/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[DataEventHandler(tableStr(PurchPurchaseOrderHeader), DataEventType::Inserting)]
public static void PurchPurchaseOrderHeader_onInserting(Common sender, DataEventArgs e)
{
    PurchPurchaseOrderHeader purchPurchaseOrderHeader = sender as PurchPurchaseOrderHeader;
    ETG_PurchTableTrade trade;
    PurchTable purchTable;

    select * from trade
        where trade.PurchId == purchPurchaseOrderHeader.PurchId;

    purchPurchaseOrderHeader.POConfirmDeliveryTerms = trade.POConfirmDeliveryTerms;

    select * from purchTable 
        where purchTable.PurchId == purchPurchaseOrderHeader.PurchId;
    purchPurchaseOrderHeader.ETGVendGSTINumber = TaxRegistrationNumbers_IN::find(TaxInformation_IN::findDefaultbyLocation(VendTable::find(purchTable.InvoiceAccount).postalAddress().Location).GSTIN).RegistrationNumber;

    if(curExt() == 'O051')
    {
        purchPurchaseOrderHeader.ETG_TermsOfPayment = purchTable.Payment;
        purchPurchaseOrderHeader.ETG_DeliveryTerms  = purchTable.DlvTerm;
    }
}
